const hits = $input.all()[0].json.hits.hits;
const maintenant = new Date().toLocaleString("fr-FR", {
  timeZone: "Africa/Tunis",
  day: "2-digit", month: "2-digit", year: "numeric",
  hour: "2-digit", minute: "2-digit"
});

let nb_critical = 0, nb_high = 0, nb_medium = 0, nb_low = 0;

hits.forEach(h => {
  const score = parseFloat(h._source.ai_score || 0);
  if (score >= 0.9)       nb_critical++;
  else if (score >= 0.75) nb_high++;
  else if (score >= 0.6)  nb_medium++;
  else                    nb_low++;
});

const lignes = hits.map(h => {
  const s = h._source;
  const score = parseFloat(s.ai_score || 0);
  const pct = (score * 100).toFixed(1);

  let severity, color;
  if (score >= 0.9)       { severity = "CRITICAL"; color = "#dc2626"; }
  else if (score >= 0.75) { severity = "HIGH";     color = "#ea580c"; }
  else if (score >= 0.6)  { severity = "MEDIUM";   color = "#d97706"; }
  else                    { severity = "LOW";       color = "#65a30d"; }

  const src_ip  = s["id.orig_h"] || s.src || "N/A";
  const dst_ip  = s["id.resp_h"] || s.dst || "N/A";
  const port    = s["id.resp_p"] || "N/A";
  const proto   = s.proto        || "N/A";
  const state   = s.conn_state   || "N/A";
  const o_bytes = s.orig_bytes   || 0;
  const r_bytes = s.resp_bytes   || 0;
  const ts      = s["@timestamp"] ? new Date(s["@timestamp"]).toLocaleString("fr-FR") : "N/A";

  return `
  <tr style="border-bottom:1px solid #1e3a5f">
    <td style="padding:10px;color:#94a3b8;font-size:12px">${ts}</td>
    <td style="padding:10px;font-weight:600;color:#60a5fa">${src_ip}</td>
    <td style="padding:10px;color:#e2e8f0">${dst_ip}</td>
    <td style="padding:10px;color:#e2e8f0">${port}</td>
    <td style="padding:10px;color:#e2e8f0">${proto}</td>
    <td style="padding:10px;color:#e2e8f0">${state}</td>
    <td style="padding:10px">
      <span style="background:${color};color:white;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:700">${severity}</span>
    </td>
    <td style="padding:10px;font-weight:700;color:${color}">${pct}%</td>
    <td style="padding:10px;color:#94a3b8;font-size:11px">${o_bytes} / ${r_bytes} B</td>
  </tr>`;
}).join("");

const rapport = `<!DOCTYPE html>
<html lang="fr">
<head><meta charset="UTF-8"><title>CyberTrace Rapport</title></head>
<body style="margin:0;padding:0;background:#0a0f1e;font-family:'Segoe UI',Arial,sans-serif;color:#e2e8f0">
<div style="max-width:950px;margin:0 auto;padding:30px">

  <div style="background:linear-gradient(135deg,#0f2544,#1a3a6e);border-radius:12px;padding:30px;margin-bottom:24px;border-left:5px solid #ef4444">
    <div style="display:flex;align-items:center;gap:15px">
      <div style="font-size:48px">🛡️</div>
      <div>
        <h1 style="margin:0;font-size:26px;color:#f8fafc">CyberTrace — Rapport d'Incidents</h1>
        <p style="margin:6px 0 0;color:#94a3b8;font-size:14px">Généré le ${maintenant} | Détection IA automatique</p>
      </div>
    </div>
  </div>

  <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:24px">
    <div style="background:#1e0a0a;border:1px solid #dc2626;border-radius:10px;padding:20px;text-align:center">
      <div style="font-size:36px;font-weight:800;color:#ef4444">${nb_critical}</div>
      <div style="color:#94a3b8;font-size:13px;margin-top:4px">🔴 CRITICAL</div>
    </div>
    <div style="background:#1a0f06;border:1px solid #ea580c;border-radius:10px;padding:20px;text-align:center">
      <div style="font-size:36px;font-weight:800;color:#f97316">${nb_high}</div>
      <div style="color:#94a3b8;font-size:13px;margin-top:4px">🟠 HIGH</div>
    </div>
    <div style="background:#1a1506;border:1px solid #d97706;border-radius:10px;padding:20px;text-align:center">
      <div style="font-size:36px;font-weight:800;color:#fbbf24">${nb_medium}</div>
      <div style="color:#94a3b8;font-size:13px;margin-top:4px">🟡 MEDIUM</div>
    </div>
    <div style="background:#0a1a0a;border:1px solid #16a34a;border-radius:10px;padding:20px;text-align:center">
      <div style="font-size:36px;font-weight:800;color:#4ade80">${hits.length}</div>
      <div style="color:#94a3b8;font-size:13px;margin-top:4px">📊 TOTAL</div>
    </div>
  </div>

  <div style="background:#1e0a0a;border:1px solid #ef4444;border-radius:10px;padding:20px;margin-bottom:24px">
    <h2 style="margin:0 0 8px;color:#ef4444;font-size:16px">⚠️ ALERTE SÉCURITÉ — Action requise</h2>
    <p style="margin:0;color:#cbd5e1;font-size:14px">
      CyberTrace a détecté <strong style="color:#ef4444">${hits.length} anomalies</strong>
      dont <strong style="color:#ef4444">${nb_critical} critiques</strong> et
      <strong style="color:#f97316">${nb_high} élevées</strong> dans les 5 dernières minutes.
    </p>
  </div>

  <div style="background:#0d1829;border:1px solid #1e3a5f;border-radius:10px;padding:24px;margin-bottom:24px">
    <h2 style="margin:0 0 16px;color:#60a5fa;font-size:18px">📋 Détails des incidents</h2>
    <div style="overflow-x:auto">
      <table style="width:100%;border-collapse:collapse;font-size:13px">
        <thead>
          <tr style="background:#0f2544">
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">Horodatage</th>
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">IP Source</th>
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">IP Dest</th>
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">Port</th>
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">Proto</th>
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">État</th>
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">Sévérité</th>
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">Score IA</th>
            <th style="padding:12px 10px;text-align:left;color:#94a3b8;border-bottom:2px solid #1e3a5f">Octets S/R</th>
          </tr>
        </thead>
        <tbody>${lignes}</tbody>
      </table>
    </div>
  </div>

  <div style="background:#0d1829;border:1px solid #1e3a5f;border-radius:10px;padding:20px;text-align:center">
    <p style="margin:0;color:#475569;font-size:12px">
      🔒 <strong style="color:#60a5fa">CyberTrace IA</strong> —
      Pipeline : PCAP → Zeek → Logstash → Elasticsearch → IA → N8N<br>
      Rapport confidentiel. Toute anomalie CRITICAL nécessite une vérification immédiate.
    </p>
  </div>

</div>
</body>
</html>`;

return [{
  json: {
    rapport_html: rapport,
    sujet: `🚨 CyberTrace — ${hits.length} anomalies (${nb_critical} CRITICAL, ${nb_high} HIGH) — ${maintenant}`,
    nb_total: hits.length,
    nb_critical,
    nb_high
  }
}];
